const emailData = {
    to: msg.payload.email,
    nombre: msg.payload.nombre,
    sector: msg.payload.sector,
    movie: msg.payload.movie,
    timeSlot: msg.payload.timeSlot,
    seats: (msg.payload.seats || []).join(', ')
};
const emailMsg = {
    payload: Buffer.from(JSON.stringify(emailData)).toString('base64'),
    email: emailData.to,
    movie: emailData.movie
};
const responseMsg = { payload: { status: 'ok' }, res: msg.res };
const dashMsg = { payload: {
    email: msg.payload.email,
    movie: msg.payload.movie,
    timeSlot: msg.payload.timeSlot,
    seats: (msg.payload.seats || []).join(', '),
    timestamp: new Date().toISOString()
}};
return [emailMsg, responseMsg, dashMsg];

const ref = msg.req.query.ref || '';
const nombre = msg.req.query.nombre || '';
node.log('Clic en enlace - email: ' + ref);
const httpMsg = { statusCode: 302, headers: { 'Location': '/educativo.html?ref=' + encodeURIComponent(ref) + '&nombre=' + encodeURIComponent(nombre) }, payload: '', res: msg.res };
const dashMsg = { payload: { email: ref, timestamp: new Date().toISOString() } };
return [httpMsg, dashMsg];

var reservations = flow.get('reservations') || [];
reservations.unshift({
    email: msg.payload.email,
    movie: msg.payload.movie,
    timeSlot: msg.payload.timeSlot,
    seats: msg.payload.seats,
    ts: Date.now() / 1000,
    hora: new Date().toLocaleTimeString('es-EC', { hour: '2-digit', minute: '2-digit', timeZone: 'America/Guayaquil' })
});
if (reservations.length > 50) reservations.pop();
flow.set('reservations', reservations);
return {};   // dispara "Refrescar panel"

var ref = msg.payload.email || '';
var clicks = flow.get('clicks') || [];
var already = clicks.some(function (c) { return c.emailFull === ref; });
if (!already && ref) {
    clicks.unshift({
        email: ref,
        emailFull: ref,
        ts: Date.now() / 1000,
        hora: new Date().toLocaleTimeString('es-EC', { hour: '2-digit', minute: '2-digit', timeZone: 'America/Guayaquil' }),
        timestamp: msg.payload.timestamp
    });
    if (clicks.length > 50) clicks.pop();
    flow.set('clicks', clicks);
}
return {};   // dispara "Refrescar panel"

var action = msg.payload.action;
var reservations = flow.get('reservations') || [];
if (action === 'delete-all') {
    reservations = [];
    flow.set('reservations', reservations);
} else if (action === 'delete-one') {
    reservations.splice(msg.payload.index, 1);
    flow.set('reservations', reservations);
}
var httpRes = { payload: { status: 'ok' }, res: msg.res };
return [httpRes, {}];   // salida 2 dispara "Refrescar panel"

var action = msg.payload.action;
var clicks = flow.get('clicks') || [];
if (action === 'delete-all') {
    clicks = [];
    flow.set('clicks', clicks);
} else if (action === 'delete-one') {
    clicks.splice(msg.payload.index, 1);
    flow.set('clicks', clicks);
}
var httpRes = { payload: { status: 'ok' }, res: msg.res };
return [httpRes, {}];   // salida 2 dispara "Refrescar panel"

const reservations = flow.get('reservations') || [];
const clicks = flow.get('clicks') || [];
// Split reservations into capturas (email submitted) and envios (email actually sent).
const capturas = reservations.map(r => ({ ts: r.ts, email: r.email, source: r.source || 'web' }));
const envios = reservations.filter(r => r.sent).map(r => ({ ts: r.sentTs || r.ts, email: r.email, status: r.sentStatus || 'ok' }));
msg.payload = { ts: Date.now()/1000, scenario: 'esc2', tables: { email_capturas: capturas, email_envios: envios, email_clicks: clicks } };
msg.headers = { 'Content-Type': 'application/json' };
return msg;

// Único punto que dibuja el panel: lee el estado y emite a los 3 templates.
var reservations = flow.get('reservations') || [];
var clicks = flow.get('clicks') || [];
var movieCounts = {};
reservations.forEach(function (r) { movieCounts[r.movie] = (movieCounts[r.movie] || 0) + 1; });
var liveMsg   = { payload: { total: reservations.length, rows: reservations } };
var statsMsg  = { payload: {
    total: reservations.length,
    clicks: clicks.length,
    rate: reservations.length > 0 ? Math.round(clicks.length / reservations.length * 100) : 0,
    movieCounts: movieCounts
}};
var clicksMsg = { payload: { total: clicks.length, rows: clicks } };
return [liveMsg, statsMsg, clicksMsg];

// Marca la reserva como enviada según el código de salida de send_email.py.
// Lo dispara la salida 3 (return code) de "Enviar email (Python)".
var rc = msg.payload || {};
var code = (typeof rc.code !== 'undefined') ? rc.code : (msg.rc ? msg.rc.code : undefined);
var ok = (code === 0);
var email = msg.email || '';
var reservations = flow.get('reservations') || [];

var idx = -1;
for (var i = 0; i < reservations.length; i++) {
    if (reservations[i].email === email && !reservations[i].sent) { idx = i; break; }
}
if (idx === -1 && !email) {          // respaldo: la reserva sin enviar más antigua
    for (var j = reservations.length - 1; j >= 0; j--) {
        if (!reservations[j].sent) { idx = j; break; }
    }
}
if (idx !== -1) {
    if (ok) {
        reservations[idx].sent = true;
        reservations[idx].sentTs = Date.now() / 1000;
        reservations[idx].sentStatus = 'ok';
    } else {
        reservations[idx].sentStatus = 'error';
        node.warn('Envío falló para ' + (email || '(desconocido)') + ' code=' + code);
    }
    flow.set('reservations', reservations);
}
return null;
